// MCP Client Helpers
// Generated by mcp-to-quickjs
// Provides shared functions for calling MCP tools via curl.
// QuickJS has no fetch() — we use os.exec + curl instead.
// Requires: qjs --std (std and os are globals provided by --std flag)

import { MCP_URL, AUTH_HEADER, MCP_SESSION_ID, MCP_PROTOCOL_VERSION } from './config.js';

let _reqCounter = 0;

// === Low-level MCP JSON-RPC request ===

/**
 * Send a raw JSON-RPC request and return the parsed result.
 * @param {string} method - JSON-RPC method (e.g. "tools/list", "tools/call")
 * @param {object} params - Parameters for the method
 * @returns {object|null} The parsed result field, or null on error
 */
export function mcpRequest(method, params) {
    let reqId = Date.now() + "_" + (_reqCounter++);
    let tmpFile = "/tmp/mcp_req_" + reqId + ".json";
    let outFile = "/tmp/mcp_resp_" + reqId + ".json";

    let request = { jsonrpc: "2.0", id: reqId, method: method, params: params };
    let body = JSON.stringify(request);

    let f = std.open(tmpFile, "w");
    f.puts(body);
    f.close();

    let curlArgs = ["curl", "-s", "-S", "-X", "POST"];
    curlArgs.push("-H", "Content-Type: application/json");
    curlArgs.push("-H", "Accept: application/json, text/event-stream");
    curlArgs.push("-H", "MCP-Protocol-Version: " + MCP_PROTOCOL_VERSION);

    if (AUTH_HEADER && AUTH_HEADER.length > 0) {
        curlArgs.push("-H", "Authorization: " + AUTH_HEADER);
    }
    if (MCP_SESSION_ID && MCP_SESSION_ID.length > 0) {
        curlArgs.push("-H", "MCP-Session-Id: " + MCP_SESSION_ID);
    }

    curlArgs.push("-d", "@" + tmpFile);
    curlArgs.push("--max-time", "30");
    curlArgs.push("--output", outFile);
    curlArgs.push(MCP_URL);

    let exitCode = os.exec(curlArgs);

    try { os.remove(tmpFile); } catch (e) {}

    let rawOutput;
    try { rawOutput = std.loadFile(outFile); } catch (e) { rawOutput = ""; }
    try { os.remove(outFile); } catch (e) {}

    if (exitCode !== 0) {
        print("ERROR: curl exited with code " + exitCode);
        if (rawOutput) print(rawOutput);
        return null;
    }

    if (!rawOutput || rawOutput.trim().length === 0) {
        print("ERROR: Empty response from server");
        return null;
    }

    // Handle SSE (Server-Sent Events) format: extract JSON from data: lines
    let response;
    let jsonStr = rawOutput;
    if (rawOutput.startsWith("event:") || rawOutput.startsWith("data:")) {
        // SSE format — find the first data: line
        let lines = rawOutput.split("\n");
        for (let line of lines) {
            if (line.startsWith("data: ")) {
                jsonStr = line.substring(6);
                break;
            }
        }
    }

    try { response = JSON.parse(jsonStr); } catch (e) {
        print("ERROR: Failed to parse response. Raw output:");
        print(rawOutput);
        return null;
    }

    if (response.error) {
        print("JSON-RPC Error (code " + response.error.code + "): " + response.error.message);
        return null;
    }

    return response.result;
}

// === Tool operations ===

/**
 * Call a tool by name with JSON arguments.
 */
export async function mcpCall(toolName, args) {
    return mcpRequest("tools/call", { name: toolName, arguments: args });
}

/**
 * Discover all available tools on the server (handles pagination).
 * @returns {Array|null} Array of tool definition objects, or null on error
 */
export async function listTools() {
    let allTools = [];
    let cursor = undefined;

    do {
        let params = {};
        if (cursor) params.cursor = cursor;
        let result = mcpRequest("tools/list", params);
        if (!result) return null;
        if (result.tools) {
            for (let tool of result.tools) allTools.push(tool);
        }
        cursor = result.nextCursor || null;
    } while (cursor);

    return allTools;
}

/**
 * Get the full definition for a specific tool (name, description, inputSchema).
 * Dynamically queries the server — no pre-loaded manifest needed.
 */
export async function getSchema(toolName) {
    let tools = await listTools();
    if (!tools) return null;
    for (let tool of tools) {
        if (tool.name === toolName) return tool;
    }
    return null;
}

// === Output helpers ===

/**
 * Print a MCP tool result to stdout.
 */
export function printResult(result) {
    if (!result) return;

    if (result.isError) {
        print("--- Tool returned an error ---");
    }

    let items = result.content;
    if (!items || items.length === 0) {
        print("(empty result)");
        return;
    }

    if (result.structuredContent) {
        print(JSON.stringify(result.structuredContent, null, 2));
        return;
    }

    for (let item of items) {
        if (item.type === "text") {
            print(item.text);
        } else if (item.type === "image") {
            print("[image: " + item.mimeType + "]");
        } else if (item.type === "resource_link") {
            print("[resource_link: " + (item.name || item.uri) + "]");
        } else if (item.type === "resource" && item.resource) {
            if (item.resource.text) {
                print(item.resource.text);
            } else {
                print("[resource: " + (item.resource.uri || "unknown") + "]");
            }
        } else {
            print(JSON.stringify(item));
        }
    }
}

/**
 * Pretty-print a tool list in a scannable format.
 */
export function printToolList(tools) {
    print("Available tools on " + MCP_URL + ":");
    print("");

    let maxLen = 0;
    for (let t of tools) {
        if (t.name.length > maxLen) maxLen = t.name.length;
    }

    for (let t of tools) {
        let pad = "";
        for (let i = t.name.length; i < maxLen; i++) pad += " ";
        print("  " + t.name + pad + "  " + (t.description || "(no description)"));
    }

    print("");
    print(tools.length + " tool(s) available.");
}

/**
 * Pretty-print a single tool's schema.
 */
export function printSchema(tool) {
    if (!tool) {
        print("Tool not found.");
        return;
    }
    print("Name: " + tool.name);
    print("Description: " + (tool.description || "(none)"));
    print("Parameters:");
    print(JSON.stringify(tool.inputSchema, null, 2));
}

/**
 * Parse a JSON string from CLI arguments.
 */
export function parseArgs(jsonStr) {
    if (!jsonStr) return {};
    try {
        return JSON.parse(jsonStr);
    } catch (e) {
        print("ERROR: Invalid JSON argument:", e.message);
        print('Usage: qjs <tool>.js \'{"param1": "val1"}\'');
        std.exit(1);
    }
}
